import{c as o,Q as a,j as e,m as d}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"Godot 2D 独立游戏开发系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"godotLearning/00-写作计划.md","filePath":"godotLearning/00-写作计划.md","lastUpdated":1779613419000}'),n={name:"godotLearning/00-写作计划.md"};function s(r,t,i,l,c,p){return a(),e("div",null,[...t[0]||(t[0]=[d(`<h1 id="godot-2d-独立游戏开发系列写作计划" tabindex="-1">Godot 2D 独立游戏开发系列写作计划 <a class="header-anchor" href="#godot-2d-独立游戏开发系列写作计划" aria-label="Permalink to &quot;Godot 2D 独立游戏开发系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第五类「跨界 / 兴趣型」重点项,⭐⭐⭐。 本系列基线版本为 <strong>Godot 4.6.x</strong>(截稿前以 <strong>4.6.3 / 2026-05-21</strong> 为参照),聚焦 <strong>2D 独立游戏工程化</strong>:用工程师视角理解场景树、节点、资源、信号、输入、物理、动画、UI、存档、渲染、性能、导出和工具链。 本系列不做&quot;照抄某个小游戏&quot;的保姆级复刻,而是围绕一个可持续演进的 2D 原型,逐层拆解独立游戏从可玩到可维护、从可维护到可发布的关键机制。</p></blockquote><hr><h2 id="核心定位" tabindex="-1">核心定位 <a class="header-anchor" href="#核心定位" aria-label="Permalink to &quot;核心定位&quot;">​</a></h2><p>这不是&quot;Godot 全家桶百科&quot;,也不是&quot;Unity 迁移手册&quot;。本系列只解决一个明确目标:</p><blockquote><p>让一个熟悉编程但不熟悉游戏引擎的人,能用 Godot 4.6 做出一款结构清楚、手感稳定、可扩展、能打包发布的 2D 独立游戏原型。</p></blockquote><p>因此本系列默认选择:</p><table tabindex="0"><thead><tr><th>维度</th><th>选择</th><th>原因</th></tr></thead><tbody><tr><td>引擎版本</td><td>Godot 4.6.x</td><td>避免 4.x API 变化造成文章漂移</td></tr><tr><td>游戏方向</td><td>2D</td><td>最适合独立开发者快速闭环,也最适合讲清 Godot 心智</td></tr><tr><td>主语言</td><td>类型化 GDScript (gradual typing)</td><td>贴近 Godot 原生工作流,代码量低,反馈快;通过类型标注换取静态分析与字节码优化</td></tr><tr><td>文章目标</td><td>机制 + 架构 + 可运行样例</td><td>不只讲&quot;怎么拖控件&quot;,要讲为什么这样组织</td></tr><tr><td>高级扩展</td><td>Shader / EditorPlugin / GDExtension / 联机</td><td>放在后段,不阻塞主线可玩原型</td></tr></tbody></table><hr><h2 id="godot-4-6-关键变更与本系列定位" tabindex="-1">Godot 4.6 关键变更与本系列定位 <a class="header-anchor" href="#godot-4-6-关键变更与本系列定位" aria-label="Permalink to &quot;Godot 4.6 关键变更与本系列定位&quot;">​</a></h2><p>4.6 stable 于 2026-01-26 发布,目前最新维护版为 4.6.3。本系列把下列变更显式纳入相关篇目,避免读者把 4.5 / 4.4 / 旧教程心智带进 4.6:</p><table tabindex="0"><thead><tr><th>变更</th><th>影响范围</th><th>本系列在哪篇展开</th></tr></thead><tbody><tr><td><strong>Jolt Physics 设为 3D 默认</strong></td><td>仅 3D,<strong>2D 物理仍是 GodotPhysics2D,无变化</strong></td><td>第 06 篇明确澄清,避免迁移焦虑</td></tr><tr><td><strong>Unique Node IDs</strong></td><td>重命名 / 重组层级时引用不再断裂;影响 <code>get_node</code> / <code>%UniqueName</code> / signal 连接习惯</td><td>第 03 / 05 篇心智段</td></tr><tr><td><strong>TileMap 自 4.3 起 deprecated</strong></td><td><code>TileMapLayer</code> 是唯一推荐路径;<code>tile_map_data</code> 是不透明 base64 PackedByteArray;16-bit 坐标边界 ±32768</td><td>第 11 篇</td></tr><tr><td><strong>Modern Editor Theme + Movable/Floatable Docks</strong></td><td>编辑器默认外观与 dock 工作流;截图与教程一致性</td><td>第 02 / 28 篇</td></tr><tr><td><strong>Direct3D 12 默认 (Windows 新项目)</strong></td><td>渲染后端选择影响导出与驱动稳定</td><td>第 26 篇</td></tr><tr><td><strong>Delta-encoded patch PCKs</strong></td><td>补丁包仅打包差异,显著减小更新体积</td><td>第 26 篇</td></tr><tr><td><strong>Physics Interpolation (4.4+)</strong></td><td>低帧率下移动平滑,影响手感与镜头</td><td>第 06 / 24 篇</td></tr><tr><td><strong>WorkerThreadPool</strong></td><td>异步任务统一调度,替代旧线程模型</td><td>第 24 篇</td></tr><tr><td><strong>LibGodot</strong></td><td>Godot 作为库被嵌入其它应用</td><td>第 25 篇延伸提及</td></tr></tbody></table><hr><h2 id="六层路线" tabindex="-1">六层路线 <a class="header-anchor" href="#六层路线" aria-label="Permalink to &quot;六层路线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>引擎心智与项目骨架</span></span>
<span class="line"><span>   → 玩家控制、物理碰撞与手感闭环</span></span>
<span class="line"><span>   → 关卡、敌人、UI、存档与可玩原型</span></span>
<span class="line"><span>   → 数据驱动、组件化、表现力与内容扩展</span></span>
<span class="line"><span>   → Shader、性能、异步加载与底层扩展</span></span>
<span class="line"><span>   → 打包发布、工具插件、联机与发售检查</span></span></code></pre></div><p>核心节奏是:<strong>前 15 篇先做出稳定可玩的 2D 原型,后 15 篇再把它做深、做漂亮、做可发布。</strong></p><hr><h2 id="篇目设计-30-篇" tabindex="-1">篇目设计 (30 篇) <a class="header-anchor" href="#篇目设计-30-篇" aria-label="Permalink to &quot;篇目设计 (30 篇)&quot;">​</a></h2><h3 id="第一层-引擎心智与项目骨架-01-05" tabindex="-1">第一层:引擎心智与项目骨架 (01-05) <a class="header-anchor" href="#第一层-引擎心智与项目骨架-01-05" aria-label="Permalink to &quot;第一层:引擎心智与项目骨架 (01-05)&quot;">​</a></h3><ul><li><strong>01 Godot 4.6 与 2D 独立游戏心智总览</strong> (为什么选 Godot / 场景树与节点哲学 / 本系列最终会做出什么)</li><li><strong>02 项目结构、资源导入与像素级基础配置</strong> (<code>project.godot</code> / 目录约定 / 纹理过滤 / 像素风与非像素风的导入差异 / <strong>4.6 Modern Editor Theme 与 Movable Docks 工作流</strong>)</li><li><strong>03 场景树、节点生命周期与主循环</strong> (<code>_ready</code> / <code>_process</code> / <code>_physics_process</code> / <code>delta</code> / 节点入树出树顺序 / <strong>4.6 Unique Node IDs 与节点引用稳定性</strong>)</li><li><strong>04 类型化 GDScript 与面向引擎编程</strong> (类型标注 / <code>@export</code> / <code>@onready</code> / 内置容器 / <code>await</code> / 常见性能陷阱)</li><li><strong>05 Resource、Signal 与场景解耦基础</strong> (<code>Resource</code> vs <code>Node</code> / <code>.tres</code> 序列化 / 自定义信号 / 生命周期与连接方式 / <strong>Unique Node IDs 对信号连接的影响</strong>)</li></ul><h3 id="第二层-玩家控制、物理碰撞与手感闭环-06-10" tabindex="-1">第二层:玩家控制、物理碰撞与手感闭环 (06-10) <a class="header-anchor" href="#第二层-玩家控制、物理碰撞与手感闭环-06-10" aria-label="Permalink to &quot;第二层:玩家控制、物理碰撞与手感闭环 (06-10)&quot;">​</a></h3><ul><li><strong>06 CharacterBody2D 与移动碰撞模型</strong> (<code>move_and_slide</code> / 速度向量 / 地面检测 / 斜坡 / 物理 Tick 调优 / <strong>澄清:4.6 Jolt 仅 3D,2D 物理仍是 GodotPhysics2D</strong> / Physics Interpolation 与帧率)</li><li><strong>07 输入映射、输入缓冲与手感参数</strong> (<code>InputMap</code> / coyote time / jump buffer / acceleration / friction / hit stop)</li><li><strong>08 AnimationPlayer、AnimationTree 与角色状态机</strong> (<code>AnimationPlayer</code> / <code>AnimatedSprite2D</code> / <code>AnimationTree</code> StateMachine / 自写 FSM 选型 / 动画与逻辑解耦)</li><li><strong>09 Collision Layer / Mask 的工程化设计</strong> (碰撞矩阵 / <code>Area2D</code> / <code>RayCast2D</code> / hurtbox-hitbox / 调试视图)</li><li><strong>10 Camera2D、屏幕震动与多分辨率视口</strong> (平滑追踪 / dead zone / screen shake / stretch mode / pixel perfect)</li></ul><h3 id="第三层-关卡、敌人、ui、存档与可玩原型-11-15" tabindex="-1">第三层:关卡、敌人、UI、存档与可玩原型 (11-15) <a class="header-anchor" href="#第三层-关卡、敌人、ui、存档与可玩原型-11-15" aria-label="Permalink to &quot;第三层:关卡、敌人、UI、存档与可玩原型 (11-15)&quot;">​</a></h3><blockquote><p>本层每篇做&quot;最小可行&quot;实现,只为跑通&quot;主菜单 → 关卡 → 死亡 → 重开&quot;闭环;深入展开留到第 16-25 层。</p></blockquote><ul><li><strong>11 TileMapLayer、TileSet 与 2D 关卡搭建</strong> (<code>TileMapLayer</code> / terrain sets / pattern / 分层碰撞 / 关卡目录组织 / <strong>TileMap 自 4.3 起 deprecated,仅用 TileMapLayer</strong>;16-bit 坐标边界与 <code>tile_map_data</code> 不透明编码踩坑)</li><li><strong>12 敌人 AI、巡逻、追击与导航网格三件套</strong> (<code>NavigationRegion2D</code> 烘焙 / <code>NavigationAgent2D</code> 代理 / <code>NavigationObstacle2D</code> 动态障碍 / 状态切换 / 伤害判定 / 击退 / 掉落物)</li><li><strong>13 HUD、菜单与 Godot UI 容器系统</strong> (<code>Control</code> / anchor / container / theme / HUD / pause menu / 背包雏形)</li><li><strong>14 存档、配置与版本迁移</strong> (JSON vs <code>Resource</code> / <code>user://</code> / schema version / 备份恢复 / 校验与轻量加密)</li><li><strong>15 场景流管理器与第一个完整可玩闭环</strong> (主菜单 / 关卡切换 / 死亡重开 / 胜利结算 / 原型质量验收)</li></ul><h3 id="第四层-数据驱动、组件化与表现力提升-16-20" tabindex="-1">第四层:数据驱动、组件化与表现力提升 (16-20) <a class="header-anchor" href="#第四层-数据驱动、组件化与表现力提升-16-20" aria-label="Permalink to &quot;第四层:数据驱动、组件化与表现力提升 (16-20)&quot;">​</a></h3><ul><li><strong>16 Autoload、事件总线与全局状态边界</strong> (什么时候用单例 / EventBus / 游戏会话状态 / 依赖方向)</li><li><strong>17 组件化设计:生命、属性、技能与效果系统</strong> (composition over inheritance / 子节点组件 / Resource 配置 / 状态效果)</li><li><strong>18 数据驱动的道具、装备与关卡配置</strong> (<code>Resource</code> 配表 / 编辑器 Inspector 工作流 / 掉落表 / 平衡性参数)</li><li><strong>19 2D 光影、法线贴图与伪 3D 质感</strong> (<code>PointLight2D</code> / <code>LightOccluder2D</code> / normal map / 层级和性能边界)</li><li><strong>20 粒子、音频总线与反馈系统</strong> (<code>GPUParticles2D</code> / <code>CPUParticles2D</code> / <code>ParticleProcessMaterial</code> / audio bus / 动态音效)</li></ul><h3 id="第五层-shader、程序化内容、性能与扩展-21-25" tabindex="-1">第五层:Shader、程序化内容、性能与扩展 (21-25) <a class="header-anchor" href="#第五层-shader、程序化内容、性能与扩展-21-25" aria-label="Permalink to &quot;第五层:Shader、程序化内容、性能与扩展 (21-25)&quot;">​</a></h3><ul><li><strong>21 CanvasItem Shader 与常见 2D 特效</strong> (描边 / 溶解 / 水波 / 闪白 / shader 参数驱动)</li><li><strong>22 程序化关卡与可控随机</strong> (<code>FastNoiseLite</code> / 随机种子 / 元胞自动机 / 房间走廊 / 生成结果可复现)</li><li><strong>23 2D 渲染性能、批处理与资源预算</strong> (draw call / texture atlas / material 切换 / Y-sort / 可见性裁剪)</li><li><strong>24 异步加载、WorkerThreadPool 与 Physics Interpolation</strong> (<code>ResourceLoader</code> threaded load / <code>WorkerThreadPool</code> / loading screen / 引用释放 / 资源泄漏排查 / <strong>4.4+ Physics Interpolation 与低帧手感</strong>)</li><li><strong>25 GDExtension 与 Rust/C++ 性能模块入门</strong> (何时不用 GDScript / GDExtension 边界 / godot-rust / 小型热点模块替换 / <strong>LibGodot 嵌入心智延伸</strong>)</li></ul><h3 id="第六层-发布、工具链、联机与长期维护-26-30" tabindex="-1">第六层:发布、工具链、联机与长期维护 (26-30) <a class="header-anchor" href="#第六层-发布、工具链、联机与长期维护-26-30" aria-label="Permalink to &quot;第六层:发布、工具链、联机与长期维护 (26-30)&quot;">​</a></h3><ul><li><strong>26 多平台导出、D3D12 与增量补丁</strong> (PC / Web / Mobile / export preset / 资源压缩 / Web 限制 / <strong>4.6 Windows D3D12 默认渲染后端 / Delta-encoded patch PCKs</strong>)</li><li><strong>27 本地化、字体与输入设备适配</strong> (Translation / 字体 fallback / 手柄键鼠 / 可访问性基础)</li><li><strong>28 EditorPlugin、Tool 脚本与一人团队提效</strong> (<code>@tool</code> / <code>EditorPlugin</code> / 自定义 dock / 自动生成配置资源 / 4.6 Movable Docks 对插件落位的影响)</li><li><strong>29 多人联机初步:RPC、Spawner、Synchronizer 三件套</strong> (High-level multiplayer / RPC / <code>MultiplayerSpawner</code> / <code>MultiplayerSynchronizer</code> / 插值与预测边界)</li><li><strong>30 发售前工程检查表、测试与长期维护策略</strong> (崩溃日志 / 存档兼容 / 设置菜单 / 版本号 / <strong>GUT 最低骨架 / <code>--headless</code> 脚本化检查 / CI 心智</strong> / itch.io/Steam 发布前清单)</li></ul><hr><h2 id="贯穿项目" tabindex="-1">贯穿项目 <a class="header-anchor" href="#贯穿项目" aria-label="Permalink to &quot;贯穿项目&quot;">​</a></h2><p>全系列使用同一个逐步演进的 2D 原型,而不是每篇从零新建孤立 demo。<strong>例外:第 25 篇(GDExtension)、第 28 篇(EditorPlugin)、第 29 篇(多人联机) 为可选扩展篇,允许使用独立最小工程演示,不强制嵌入主线原型。</strong></p><table tabindex="0"><thead><tr><th>阶段</th><th>原型状态</th><th>验收标准</th></tr></thead><tbody><tr><td>01-05</td><td>空项目骨架</td><td>目录结构、资源导入、基础场景、基础脚本规范确定</td></tr><tr><td>06-10</td><td>可操控角色</td><td>移动、跳跃、受击、镜头、动画状态都能稳定运行</td></tr><tr><td>11-15</td><td>可玩小关卡</td><td>有关卡、敌人、HUD、存档、菜单、胜负闭环</td></tr><tr><td>16-20</td><td>可扩展玩法</td><td>道具、属性、效果、反馈系统可以通过数据配置扩展</td></tr><tr><td>21-25</td><td>高级表现与性能</td><td>有 Shader、程序化内容、加载页、性能预算与一个扩展模块</td></tr><tr><td>26-30</td><td>可发布原型</td><td>能导出、能本地化、能配置输入、具备发售前检查清单</td></tr></tbody></table><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>向量、插值、概率和噪声数学</td><td>mathForCS</td><td>只讲在 Godot 2D 移动、镜头、寻路和程序化关卡中的工程用法</td></tr><tr><td>组件化、观察者、状态机</td><td>designPatternLearning</td><td>不重复模式定义,只讲 Godot 场景树、子节点组件和 Resource 配置落地</td></tr><tr><td>存档校验、加密与作弊</td><td>securityLearning</td><td>不讲密码学推导,只讲本地存档保护、版本迁移和破坏恢复</td></tr><tr><td>网络协议与同步底层</td><td>networkLearning</td><td>不重复 TCP/UDP 基础,只讲 Godot 高层多人 API 与同步心智</td></tr><tr><td>Rust/C++ 语言基础</td><td>rustLearning / goLearning</td><td>不讲语言语法,只讲 GDExtension 作为热点模块边界</td></tr><tr><td>前端 UI 与响应式布局</td><td>webLearning</td><td>不重复 Web UI,只讲 Godot <code>Control</code>、容器、主题和游戏 HUD</td></tr></tbody></table><hr><h2 id="单篇写作模板" tabindex="-1">单篇写作模板 <a class="header-anchor" href="#单篇写作模板" aria-label="Permalink to &quot;单篇写作模板&quot;">​</a></h2><p>每篇遵循固定结构,避免变成散点知识:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 机制定位</span></span>
<span class="line"><span>   - 这个机制在 2D 游戏里解决什么核心问题</span></span>
<span class="line"><span>   - 新手常见写法为什么会失控</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Godot 心智</span></span>
<span class="line"><span>   - 对应核心类、节点和资源</span></span>
<span class="line"><span>   - 生命周期、数据流和依赖方向</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工程实现</span></span>
<span class="line"><span>   - 30-120 行可运行 GDScript</span></span>
<span class="line"><span>   - 静态类型、信号声明、导出参数和目录位置</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 调参和验收</span></span>
<span class="line"><span>   - 哪些参数直接影响手感、性能或稳定性</span></span>
<span class="line"><span>   - 如何验证这一篇真的完成了</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 踩坑</span></span>
<span class="line"><span>   - Godot 4.6 下的常见坑</span></span>
<span class="line"><span>   - 与旧版教程、旧 API、错误心智的区别</span></span></code></pre></div><hr><h2 id="交付标准" tabindex="-1">交付标准 <a class="header-anchor" href="#交付标准" aria-label="Permalink to &quot;交付标准&quot;">​</a></h2><p>不是每篇都强制新建一个完整工程,而是维护一个贯穿式示例项目,并在关键机制处提供最小复现。</p><table tabindex="0"><thead><tr><th>交付物</th><th>要求</th></tr></thead><tbody><tr><td>Markdown 正文</td><td>讲清机制、设计取舍、实现步骤、踩坑边界</td></tr><tr><td>示例项目</td><td><code>godotLearning/demo/</code> 中维护同一个可运行 Godot 4.6 项目</td></tr><tr><td>代码风格</td><td>类型化 GDScript、清晰目录、少用全局单例</td></tr><tr><td>图解</td><td>每层至少 1 张机制图;关键篇补场景树、碰撞矩阵、数据流图</td></tr><tr><td>验收</td><td>每篇末尾给出手动验证步骤;关键篇补 GUT 或 <code>--headless</code> 脚本化检查</td></tr><tr><td>官方指针</td><td>标注核心类名,如 <code>CharacterBody2D</code>、<code>TileMapLayer</code>、<code>Resource</code>、<code>Control</code>、<code>CanvasItem</code></td></tr></tbody></table><hr><h2 id="章节节奏" tabindex="-1">章节节奏 <a class="header-anchor" href="#章节节奏" aria-label="Permalink to &quot;章节节奏&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05 建心智:理解 Godot 4.6 的项目、场景树、生命周期、类型化 GDScript、Resource 与 Signal</span></span>
<span class="line"><span>06-10 做手感:角色能动、能跳、能撞、能演出、镜头稳定</span></span>
<span class="line"><span>11-15 做游戏:关卡、敌人、UI、存档和场景流形成第一个完整闭环</span></span>
<span class="line"><span>16-20 做架构:用数据驱动和组件化降低后续内容扩展成本</span></span>
<span class="line"><span>21-25 做深度:Shader、程序化、性能、异步加载和扩展模块</span></span>
<span class="line"><span>26-30 做发布:导出、本地化、工具插件、联机入门和发售检查</span></span></code></pre></div>`,49)])])}const u=o(n,[["render",s]]);export{g as __pageData,u as default};
